import{_ as e,c as r,o as t,a as i}from"./app.d756f752.js";const q=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[{"level":2,"title":"import和require的区别","slug":"import和require的区别","link":"#import和require的区别","children":[]}],"relativePath":"6.其他/面试题整理/all.md","lastUpdated":1678715466000}'),p={name:"6.其他/面试题整理/all.md"},o=i('<h2 id="import和require的区别" tabindex="-1">import和require的区别 <a class="header-anchor" href="#import和require的区别" aria-hidden="true">#</a></h2><p>import是ES6标准中的模块化解决方案，require是node中遵循CommonJS规范的模块化解决方案</p><p>import在代码编译时被加载，所以必须放在文件开头，require在代码运行时被加载，所以require理论上可以运用在代码的任何地方，所以import性能更好</p><p>import引入的对象被修改时，源对象也会被修改，相当于浅拷贝，require引入的对象被修改时，源对象不会被修改，官网称值拷贝，我们可以理解为深拷贝</p><p>import有利于tree-shaking（移除JavaScript上下文中未引用的代码），require对tree-shaking不友好。</p><p>import会触发代码分割（把代码分离到不同的bundle中，然后可以按需加载或者并行加载这些文件），require不会触发</p><p>import是es6的一个语法标准，如果要兼容浏览器的话必须转化成es5的语法，require 是 AMD规范引入方式</p><p>目前所有的引擎都还没有实现import，import最终都会被转码为require，在webpack打包中，import和require都会变为<code>_webpack_require_</code></p>',8),a=[o];function _(s,n,c,m,d,u){return t(),r("div",null,a)}const h=e(p,[["render",_]]);export{q as __pageData,h as default};
